# 리팩토링 결과

```tsx
// Card.tsx
interface CardProps {
  title: string;
  subtitle: string;
  badge: { label: string; color: 'blue' | 'green' | 'orange' };
  onClick?: () => void;
}

export function Card({ title, subtitle, badge, onClick }: CardProps) {
  const colorMap = {
    blue: 'bg-blue-100 text-blue-800',
    green: 'bg-green-100 text-green-800',
    orange: 'bg-orange-100 text-orange-800',
  };

  return (
    <div className="card" onClick={onClick}>
      <h2>{title}</h2>
      <p>{subtitle}</p>
      <span className={`badge ${colorMap[badge.color]}`}>{badge.label}</span>
    </div>
  );
}
```

## 사용 예시

```tsx
<Card
  title={user.name}
  subtitle={user.email}
  badge={{ label: user.role, color: 'blue' }}
/>

<Card
  title={product.title}
  subtitle={product.description}
  badge={{ label: product.category, color: 'green' }}
/>
```
